                Element audienceRestriction = (Element) audienceRestrictions.item(i);
                NodeList audienceElements = getDirectChildElements(
                    audienceRestriction, SAML2_ASSERTION_NS, "Audience");
                for (int j = 0; j < audienceElements.getLength(); j++) {
                    audiences.add(audienceElements.item(j).getTextContent().trim());
                }
