    private String extractIssuer(Element assertionElement) throws SamlProcessingException {
        NodeList issuerList = getDirectChildElements(assertionElement, SAML2_ASSERTION_NS, "Issuer");
        if (issuerList.getLength() == 0) {
            throw new SamlProcessingException("Assertion missing required Issuer element");
        }
        String issuer = issuerList.item(0).getTextContent().trim();
        if (issuer.isEmpty()) {
            throw new SamlProcessingException("Assertion Issuer is empty");
        }
        return issuer;
    }

    private String extractNameId(Element assertionElement) throws SamlProcessingException {
        NodeList subjectList = getDirectChildElements(assertionElement, SAML2_ASSERTION_NS, "Subject");
        if (subjectList.getLength() == 0) {
            throw new SamlProcessingException("Assertion missing required Subject element");
        }

        Element subject = (Element) subjectList.item(0);
        NodeList nameIdList = getDirectChildElements(subject, SAML2_ASSERTION_NS, "NameID");
        if (nameIdList.getLength() == 0) {
            throw new SamlProcessingException("Subject missing required NameID element");
        }

        String nameId = nameIdList.item(0).getTextContent().trim();
        if (nameId.isEmpty()) {
            throw new SamlProcessingException("NameID is empty");
        }
        return nameId;
    }

    private String extractNameIdFormat(Element assertionElement) {
        NodeList subjectList = getDirectChildElements(assertionElement, SAML2_ASSERTION_NS, "Subject");
        if (subjectList.getLength() > 0) {
            Element subject = (Element) subjectList.item(0);
            NodeList nameIdList = getDirectChildElements(subject, SAML2_ASSERTION_NS, "NameID");
            if (nameIdList.getLength() > 0) {
                return ((Element) nameIdList.item(0)).getAttribute("Format");
            }
        }
        return null;
    }

    private void validateSubjectConfirmation(Element assertionElement) throws SamlProcessingException {
        NodeList subjectList = getDirectChildElements(assertionElement, SAML2_ASSERTION_NS, "Subject");
        if (subjectList.getLength() == 0) {
            return;
        }

        Element subject = (Element) subjectList.item(0);
        NodeList confirmations = getDirectChildElements(
            subject, SAML2_ASSERTION_NS, "SubjectConfirmation");

        boolean hasBearerConfirmation = false;
        for (int i = 0; i < confirmations.getLength(); i++) {
            Element confirmation = (Element) confirmations.item(i);
            String method = confirmation.getAttribute("Method");
            if ("urn:oasis:names:tc:SAML:2.0:cm:bearer".equals(method)) {
                hasBearerConfirmation = true;

                // Validate SubjectConfirmationData
                NodeList confirmationData = getDirectChildElements(
                    confirmation, SAML2_ASSERTION_NS, "SubjectConfirmationData");
                if (confirmationData.getLength() > 0) {
                    Element data = (Element) confirmationData.item(0);

                    // Check NotOnOrAfter
                    String notOnOrAfterStr = data.getAttribute("NotOnOrAfter");
                    if (notOnOrAfterStr != null && !notOnOrAfterStr.isEmpty()) {
                        Instant notOnOrAfter = parseInstant(notOnOrAfterStr);
                        Instant now = Instant.now();
                        if (now.isAfter(notOnOrAfter.plusSeconds(clockSkewSeconds))) {
                            throw new SamlProcessingException(
                                "SubjectConfirmationData has expired. NotOnOrAfter: " + notOnOrAfterStr);
                        }
                    }

                    // Check Recipient (should match our ACS URL)
                    if (expectedDestination != null) {
                        String recipient = data.getAttribute("Recipient");
                        if (recipient != null && !recipient.isEmpty() &&
                            !expectedDestination.equals(recipient)) {
                            throw new SamlProcessingException(
                                "SubjectConfirmationData Recipient mismatch. Expected: " +
                                expectedDestination + ", Got: " + recipient);
                        }
                    }
                }
                break;
            }
        }

        if (confirmations.getLength() > 0 && !hasBearerConfirmation) {
            throw new SamlProcessingException(
                "No bearer SubjectConfirmation found in the assertion");
        }
    }

    private Map<String, List<String>> extractAttributes(Element assertionElement) {
        Map<String, List<String>> attributes = new HashMap<>();

        NodeList attrStatements = getDirectChildElements(
            assertionElement, SAML2_ASSERTION_NS, "AttributeStatement");

        for (int i = 0; i < attrStatements.getLength(); i++) {
            Element attrStatement = (Element) attrStatements.item(i);
            NodeList attrElements = getDirectChildElements(
                attrStatement, SAML2_ASSERTION_NS, "Attribute");

            for (int j = 0; j < attrElements.getLength(); j++) {
                Element attrElement = (Element) attrElements.item(j);
                String name = attrElement.getAttribute("Name");
                if (name == null || name.isEmpty()) {
                    continue;
                }

                List<String> values = new ArrayList<>();
                NodeList valueElements = getDirectChildElements(
                    attrElement, SAML2_ASSERTION_NS, "AttributeValue");
                for (int k = 0; k < valueElements.getLength(); k++) {
                    values.add(valueElements.item(k).getTextContent().trim());
                }

                attributes.put(name, values);
            }
        }

        return attributes;
    }

    /**
     * Validate assertion conditions including time validity and audience restriction.
     */
    private void validateAssertionConditions(SamlAssertion assertion) throws SamlProcessingException {
        Instant now = Instant.now();

        // Validate time conditions
        if (assertion.getNotBefore() != null) {
            Instant adjustedNotBefore = assertion.getNotBefore().minusSeconds(clockSkewSeconds);
            if (now.isBefore(adjustedNotBefore)) {
                throw new SamlProcessingException(
                    "Assertion is not yet valid. NotBefore: " + assertion.getNotBefore() +
                    ", Current time: " + now);
            }
        }

        if (assertion.getNotOnOrAfter() != null) {
            Instant adjustedNotOnOrAfter = assertion.getNotOnOrAfter().plusSeconds(clockSkewSeconds);
            if (now.isAfter(adjustedNotOnOrAfter)) {
                throw new SamlProcessingException(
                    "Assertion has expired. NotOnOrAfter: " + assertion.getNotOnOrAfter() +
                    ", Current time: " + now);
            }
        }

        // Validate audience restriction
        if (!assertion.getAudiences().isEmpty()) {
            boolean audienceMatch = false;
            for (String audience : assertion.getAudiences()) {
                if (expectedAudience.equals(audience)) {
                    audienceMatch = true;
                    break;
                }
            }
            if (!audienceMatch) {
                throw new SamlProcessingException(
                    "Audience restriction validation failed. Expected: " +
                    expectedAudience + ", Got: " + assertion.getAudiences());
            }
        }
    }

    /**
     * Get direct child elements with a specific namespace and local name.
     * SECURITY: Only gets direct children to prevent XPath injection and
     * signature wrapping attacks that insert elements deeper in the tree.
     */
    private NodeList getDirectChildElements(Element parent, String namespaceUri, String localName) {
        List<Element> matchingElements = new ArrayList<>();
        org.w3c.dom.Node child = parent.getFirstChild();
        while (child != null) {
            if (child instanceof Element) {
                Element element = (Element) child;
                if (localName.equals(element.getLocalName()) &&
                    namespaceUri.equals(element.getNamespaceURI())) {
                    matchingElements.add(element);
                }
            }
            child = child.getNextSibling();
        }

        // Return as a simple NodeList implementation
        return new NodeList() {
            @Override
            public org.w3c.dom.Node item(int index) {
                return index >= 0 && index < matchingElements.size() ? matchingElements.get(index) : null;
            }

            @Override
            public int getLength() {
                return matchingElements.size();
            }
        };
    }

    private Instant parseInstant(String value) throws SamlProcessingException {
        try {
            return Instant.parse(value);
        } catch (DateTimeParseException e) {
            throw new SamlProcessingException("Invalid datetime format: " + value, e);
        }
    }

    // ==================== Data Classes ====================

    /**
     * Represents a parsed and validated SAML Assertion.
     */
    public static class SamlAssertion {
        private final String id;
        private final String issuer;
        private final String nameId;
        private final String nameIdFormat;
        private final Instant notBefore;
        private final Instant notOnOrAfter;
        private final List<String> audiences;
        private final Instant authnInstant;
        private final String sessionIndex;
        private final Map<String, List<String>> attributes;

        public SamlAssertion(String id, String issuer, String nameId, String nameIdFormat,
                             Instant notBefore, Instant notOnOrAfter, List<String> audiences,
                             Instant authnInstant, String sessionIndex,
                             Map<String, List<String>> attributes) {
            this.id = id;
            this.issuer = issuer;
            this.nameId = nameId;
            this.nameIdFormat = nameIdFormat;
            this.notBefore = notBefore;
            this.notOnOrAfter = notOnOrAfter;
            this.audiences = Collections.unmodifiableList(new ArrayList<>(audiences));
            this.authnInstant = authnInstant;
            this.sessionIndex = sessionIndex;
            this.attributes = Collections.unmodifiableMap(new HashMap<>(attributes));
        }

        public String getId() { return id; }
        public String getIssuer() { return issuer; }
        public String getNameId() { return nameId; }
        public String getNameIdFormat() { return nameIdFormat; }
        public Instant getNotBefore() { return notBefore; }
        public Instant getNotOnOrAfter() { return notOnOrAfter; }
        public List<String> getAudiences() { return audiences; }
        public Instant getAuthnInstant() { return authnInstant; }
        public String getSessionIndex() { return sessionIndex; }
        public Map<String, List<String>> getAttributes() { return attributes; }

        public String getAttributeValue(String name) {
            List<String> values = attributes.get(name);
            return (values != null && !values.isEmpty()) ? values.get(0) : null;
        }

        public List<String> getAttributeValues(String name) {
            List<String> values = attributes.get(name);
            return values != null ? values : Collections.emptyList();
        }

        @Override
        public String toString() {
            return "SamlAssertion{id='" + id + "', issuer='" + issuer +
                "', nameId='" + nameId + "', attributes=" + attributes.keySet() + "}";
        }
    }

    /**
     * Represents an authenticated session created from a SAML assertion.
     */
    public static class AuthenticatedSession {
        private final String sessionId;
        private final String userId;
        private final String issuer;
        private final Instant createdAt;
        private final Instant expiresAt;
        private final String samlSessionIndex;
        private final Map<String, List<String>> userAttributes;

        public AuthenticatedSession(String sessionId, String userId, String issuer,
                                     Instant createdAt, Instant expiresAt,
                                     String samlSessionIndex,
                                     Map<String, List<String>> userAttributes) {
            this.sessionId = sessionId;
            this.userId = userId;
            this.issuer = issuer;
            this.createdAt = createdAt;
            this.expiresAt = expiresAt;
            this.samlSessionIndex = samlSessionIndex;
            this.userAttributes = Collections.unmodifiableMap(new HashMap<>(userAttributes));
        }

        public String getSessionId() { return sessionId; }
        public String getUserId() { return userId; }
        public String getIssuer() { return issuer; }
        public Instant getCreatedAt() { return createdAt; }
        public Instant getExpiresAt() { return expiresAt; }
        public String getSamlSessionIndex() { return samlSessionIndex; }
        public Map<String, List<String>> getUserAttributes() { return userAttributes; }

        public boolean isExpired() {
            return Instant.now().isAfter(expiresAt);
        }

        public String getUserAttribute(String name) {
            List<String> values = userAttributes.get(name);
            return (values != null && !values.isEmpty()) ? values.get(0) : null;
        }

        @Override
        public String toString() {
            return "AuthenticatedSession{sessionId='" + sessionId +
                "', userId='" + userId + "', issuer='" + issuer +
                "', expiresAt=" + expiresAt + "}";
        }
    }

    /**
     * Session manager for creating and managing authenticated sessions.
     */
    public static class SessionManager {
        private final ConcurrentHashMap<String, AuthenticatedSession> sessions = new ConcurrentHashMap<>();
        private static final long DEFAULT_SESSION_DURATION_SECONDS = 3600; // 1 hour

        public AuthenticatedSession createSession(SamlAssertion assertion) {
            String sessionId = UUID.randomUUID().toString();
            Instant now = Instant.now();

            // Use assertion expiry or default session duration
            Instant expiresAt;
            if (assertion.getNotOnOrAfter() != null) {
                expiresAt = assertion.getNotOnOrAfter();
            } else {
                expiresAt = now.plusSeconds(DEFAULT_SESSION_DURATION_SECONDS);
            }

            AuthenticatedSession session = new AuthenticatedSession(
                sessionId,
                assertion.getNameId(),
                assertion.getIssuer(),
                now,
                expiresAt,
                assertion.getSessionIndex(),
                assertion.getAttributes()
            );

            sessions.put(sessionId, session);
            return session;
        }

        public AuthenticatedSession getSession(String sessionId) {
            AuthenticatedSession session = sessions.get(sessionId);
            if (session != null && session.isExpired()) {
                sessions.remove(sessionId);
                return null;
            }
            return session;
        }

        public void invalidateSession(String sessionId) {
            sessions.remove(sessionId);
        }

        public void invalidateBySessionIndex(String samlSessionIndex) {
            if (samlSessionIndex == null) return;
            sessions.entrySet().removeIf(entry ->
                samlSessionIndex.equals(entry.getValue().getSamlSessionIndex()));
        }

        public void cleanExpiredSessions() {
            sessions.entrySet().removeIf(entry -> entry.getValue().isExpired());
        }
    }

    /**
     * Custom exception for SAML processing errors.
     */
    public static class SamlProcessingException extends Exception {
        public SamlProcessingException(String message) {
            super(message);
        }

        public SamlProcessingException(String message, Throwable cause) {
            super(message, cause);
        }
    }

    // ==================== Utility Methods ====================

    /**
     * Load an X509 certificate from a PEM-encoded string.
     */
    public static X509Certificate loadCertificateFromPem(String pemCertificate) throws Exception {
        String cleaned = pemCertificate
            .replace("-----BEGIN CERTIFICATE-----", "")
            .replace("-----END CERTIFICATE-----", "")
            .replaceAll("\\s", "");

        byte[] decoded = Base64.getDecoder().decode(cleaned);
        CertificateFactory factory = CertificateFactory.getInstance("X.509");
        return (X509Certificate) factory.generateCertificate(new ByteArrayInputStream(decoded));
    }

    public SessionManager getSessionManager() {
        return sessionManager;
    }

